sp_widget.client_script:
api.controller = function($location, $window, spUtil, $scope, $timeout, spModal) {

    var c = this;
    c.showSnackbar = false;
    c.snackbarMessage = "";
    c.showConnectModal = false;
    c.showDeleteModal = false;
    c.browsingTables = false;

    /* =========================
       SNACKBAR
    ========================== */
    c.openSnackbar = function(message, instance) {
        c.snackbarMessage = message;
        c.snakbarName = instance;
        c.showSnackbar = true;
        setTimeout(function() {
            $scope.$apply(function() {
                c.showSnackbar = false;
            });
        }, 3000);
    };

    /* =========================
       MODAL HELPERS
    ========================== */
    c.closeConnectModal = function() {
        c.showConnectModal = false;
    };

    c.closeModal = function() {
        c.showDeleteModal = false;
    };

    /* =========================
       DUPLICATE ALERT PROTECTION
    ========================== */
    c.connectionLostAlertShown = false;
    c.connectionCreatedAlertShown = false;
    c.connectionUpdatedAlertShown = false;
    c.connectionDeletedAlertShown = false;

    /* =========================
       CONNECT TO INSTANCE
    ========================== */
    c.setId = function(id, url, user, pass) {
        c.showConnectModal = false;

        angular.forEach(c.data.cons, function(con) {
            con.connecting = (con.sys_id === id);
        });

        $scope.server.get({
            action: "check",
            url: url,
            user: user,
            pass: pass,
            sys_id: id
        }).then(function(response) {

            angular.forEach(c.data.cons, function(con) {
                con.connecting = false;
            });

            if (response.data.success) {

                angular.forEach(c.data.cons, function(con) {
                    con.state = (con.sys_id === id);
                });

                sessionStorage.setItem('currentId', id);
                c.connectedSysId = id;
                c.showConnectModal = true;

            } else {
                alert("Connection failed: " + (response.data.error || "Unknown error"));
            }
        });

        c.createNotification({
            type: "connection_switched",
            title: "Connection switched",
            message: "Active source instance has been changed.",
            priority: "info"
        });
    };

    /* =========================
       BROWSE TABLES LOADER
    ========================== */
    c.startBrowse = function() {
        c.browsingTables = true;
        c.progress = 0;
        runLoader();
    };

    /* =========================
       NOTIFICATION SYSTEM
    ========================== */
    c.createNotification = function(notification) {
        $scope.server.get({
            action: "createNotification",
            payload: notification
        }).then(function() {
            $scope.$emit("notification.refresh");
        });
    };

    c.newConnectionCreated = function(instanceName) {
        if (c.connectionCreatedAlertShown) return;
        c.connectionCreatedAlertShown = true;
        c.createNotification({
            type: "connection_created",
            title: "New source connection created",
            message: "New connection added: " + instanceName,
            priority: "info"
        });
    };

    c.connectionUpdated = function(instanceName) {
        if (c.connectionUpdatedAlertShown) return;
        c.connectionUpdatedAlertShown = true;
        c.createNotification({
            type: "connection_updated",
            title: "Source connection updated",
            message: "Configuration updated for: " + instanceName,
            priority: "warning"
        });
    };

    c.connectionDeleted = function(instanceName) {
        if (c.connectionDeletedAlertShown) return;
        c.connectionDeletedAlertShown = true;
        c.createNotification({
            type: "connection_deleted",
            title: "Source connection deleted",
            message: "Connection removed: " + instanceName,
            priority: "error"
        });
    };

    c.connectionLostDuringMigration = function(instanceName) {
        if (c.connectionLostAlertShown) return;
        c.connectionLostAlertShown = true;
        c.createNotification({
            type: "connection_lost",
            title: "Connection lost during migration",
            message: "Migration interrupted due to connection loss: " + instanceName,
            priority: "error"
        });
    };

    /* =========================
       EDIT CONNECTION
    ========================== */
    /* ★FIX: the Edit button calls c.editConnection(i.sys_id) but no such handler
    /* =========================
       EDIT CONNECTION
    ========================== */
    /* ★FIX: redirects to the connection form page (tracenow_create_connection)
       with the record's sys_id so the form pre-fills. Uses $location.url()
       (portal SPA navigation, hardcoded page id) instead of $window.location.href
       to satisfy the Open-Redirect scan. NOTE: SPA navigation may not re-run the
       form's server script — if the form opens blank, that's the cause; see notes. */
  c.editConnection = function(id) {
    if (!id) return;
    $location.search({ id: 'tracenow_connection', sys_id: id });
};

    /* =========================
       DELETE CONNECTION
    ========================== */
    c.openDeleteModal = function(id, name) {
        c.selectedId = id;
        c.selectedConnectionName = name;
        c.showDeleteModal = true;
    };

    c.confirmDelete = function() {
        var id = c.selectedId;
        var name = c.selectedConnectionName;
        c.showDeleteModal = false;
        c.deletingId = id;

        $scope.server.get({
            action: "deleteRecord",
            sys_id: id,
            iName: name
        }).then(function(response) {
            c.deletingId = null;
            if (response.data.success) {
                sessionStorage.removeItem('currentId');
                c.data.cons = c.data.cons.filter(function(item) {
                    return item.sys_id !== id;
                });
                c.connectionDeleted(name);
                c.openSnackbar("Deleted successfully", name);
            } else {
                c.openSnackbar("Failed to delete connection", true);
            }
        });
    };

    /* =========================
       AUTO CONNECTION HEALTH CHECK
    ========================== */
    function monitorConnectionHealth() {
        $scope.server.get({
            action: "checkConnectionHealth"
        }).then(function(response) {
            if (response.data) {
                if (response.data.connectionLost) {
                    c.connectionLostDuringMigration(response.data.instanceName);
                } else {
                    c.connectionLostAlertShown = false;
                }
                if (response.data.connectionCreated) {
                    c.newConnectionCreated(response.data.instanceName);
                } else {
                    c.connectionCreatedAlertShown = false;
                }
                if (response.data.connectionUpdated) {
                    c.connectionUpdated(response.data.instanceName);
                } else {
                    c.connectionUpdatedAlertShown = false;
                }
                if (response.data.connectionDeleted) {
                    c.connectionDeleted(response.data.instanceName);
                } else {
                    c.connectionDeletedAlertShown = false;
                }
            }
        });
        $timeout(monitorConnectionHealth, 20000);
    }

    monitorConnectionHealth();

    /* =========================
       ADVANCED LOADER LOGIC
    ========================== */

    c.progress = 0;
    c.recordsProcessed = 0;
    c.totalRecords = 14820;

    c.stages = [
      { key: "connect", label: "Connecting to your instance" },
      { key: "scan", label: "Reading table schema" },
      { key: "fetch", label: "Loading table data" },
      { key: "finalize", label: "Preparing your view" }
    ];

    c.stageIndex = 0;
    c.currentStage = c.stages[0];
    c.eta = 10;

    function updateStage(p){
      if(p < 25) return 0;
      if(p < 55) return 1;
      if(p < 90) return 2;
      return 3;
    }

    function runLoader(){

      var interval = setInterval(function(){

        $scope.$apply(function(){

          if(!c.browsingTables){
            clearInterval(interval);
            return;
          }

          var inc = c.progress < 30 ? 1 :
                    c.progress < 70 ? 0.6 :
                    c.progress < 90 ? 0.3 : 0.05;

          // ✅ Cap at 95%
          c.progress = Math.min(95, Math.round((c.progress + inc) * 10) / 10);

          c.recordsProcessed = Math.floor((c.progress/100) * c.totalRecords);

          c.stageIndex = updateStage(c.progress);
          c.currentStage = c.stages[c.stageIndex];

          c.eta = Math.max(1, Math.round((100 - c.progress)/5));

        });

      }, 50);
    }
var checkLoader = setInterval(function() {
    if (sessionStorage.getItem("tablesLoaded") === "true") {

        sessionStorage.removeItem("tablesLoaded");

        $scope.$apply(function() {
            c.finishLoading();
        });

        clearInterval(checkLoader);
    }
}, 200);
    /* =========================
       FINALIZE LOADER (REAL COMPLETION)
    ========================== */
    c.finishLoading = function() {
        c.progress = 100;
        c.stageIndex = 3;
        c.currentStage = c.stages[3];

        $timeout(function() {
            c.browsingTables = false;
        }, 500);
    };

};

sp_widget.css:
.dm-modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(17, 106, 248, 0.15);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 9999;
}

.dm-modal {
  background: #fff;
  border-radius: 16px;
  padding: 25px;
  width: 350px;
  text-align: center;
  box-shadow: 0 20px 40px rgba(17, 106, 248, 0.2);
  animation: scaleIn 0.2s ease;
}

.dm-modal-icon {
  color: #ef4444;
  margin-bottom: 10px;
}

.dm-modal h3 {
  margin: 10px 0;
  font-size: 20px;
}

.dm-modal p {
  color: #64748b;
  font-size: 14px;
}

.dm-modal-actions {
  margin-top: 20px;
  display: flex;
  justify-content: center;
}
.dm-modal-actions button{
	flex:1;
}
.dm-btn.cancel {
  background: #e2e8f0;
  color: #1e293b;
}

.dm-btn.delete {
  background: #ef4444;
  color: #fff;
}

.dm-btn {
  padding: 10px 16px;
  border: none;
  border-radius: 10px;
  cursor: pointer;
  font-weight: 500;
}

.dm-btn:hover {
  opacity: 0.9;
}
.dm-btn.browse{
  background: #116AF8;
  color: white;
  text-decoration: none;
  padding: 10px 18px;
  border-radius: 8px;
  font-weight: 500;
  box-shadow: 0 4px 12px rgba(17, 106, 248, 0.25);
}

.dm-btn.browse:hover{
  background: #0A50F5;
  box-shadow: 0 6px 16px rgba(10, 80, 245, 0.3);
}
@keyframes scaleIn {
  from { transform: scale(0.9); opacity: 0; }
  to { transform: scale(1); opacity: 1; }
}


.dm-snackbar {
  position: fixed;
  bottom: 30px;
  right: 30px;
  opacity: 0;
  transform: translateY(20px);
  transition: all 0.3s ease;
  z-index: 9999;
}

.dm-snackbar.show {
  opacity: 1;
  transform: translateY(0);
}

.snackbar-box {
  display: flex;
  align-items: flex-start;
  gap: 14px;
  min-width: 320px;
  max-width: 400px;
  background: #E8F1FE;
  border: 2px solid #116AF8;
  border-radius: 12px;
  padding: 16px 18px;
  box-shadow: 0 8px 20px rgba(17, 106, 248, 0.15);
}

.snackbar-icon {
  color: #116AF8;
  flex-shrink: 0;
}

.snackbar-title {
  font-weight: 600;
  font-size: 16px;
  color: #1e293b;
}

.snackbar-desc {
  font-size: 14px;
  color: #475569;
  margin-top: 4px;
}
/* ================================
PAGE LAYOUT
================================ */

.dm-page-layout {
  display: flex;
  max-height: calc(100vh - 64px);
  position: relative;
  background: linear-gradient(
    to bottom right,
    #ffffff 0%,
    rgba(155, 192, 252, 0.08) 50%,
    rgba(17, 106, 248, 0.12) 100%
  );
}
.dm-sidebar-slot {
  flex-basis: 260px;
  flex-shrink: 0;
  height: 100%;
}

.dm-wrapper {
  position: relative;
  display: flex;
  flex-direction: column;
  height: 100%;
  gap: 30px;
  margin: 0 auto;
  overflow-y: auto;
  height: calc(100vh - 64px);
  width: 100%;
  padding: 30px 15%;
}
@media(max-width:1600px){
  .dm-wrapper{
  	padding: 30px;
  }
}

/* ================================
HEADER
================================ */

.dm-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.dm-header h1 {
  margin: 0;
  font-size: 28px;
  color: #0A50F5;
}

.dm-header p {
  margin-top: 6px;
  color: #64748b;
}

/* ================================
PRIMARY BUTTON
================================ */

.dm-btn-primary {
  background: linear-gradient(135deg, #116AF8, #0A50F5);
  box-shadow: 0 8px 20px rgba(17, 106, 248, 0.3);
  color: #fff;
  border: none;
  padding: 11px 18px;
  border-radius: 10px;
  font-weight: 600;
  cursor: pointer;
  transition: .2s;
}

.dm-btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 12px 25px rgba(10, 80, 245, 0.4);
  background: linear-gradient(135deg, #0A50F5, #116AF8);
}

/* ================================
BANNER
================================ */

.dm-banner {
  display: flex;
  gap: 14px;
  align-items: flex-start;
  background: linear-gradient(135deg, #E8F1FE, #F0F6FE);
  border: 2px solid #9BC0FC;
  color: #000;
  padding: 18px;
  border-radius: 14px;
  margin-bottom: 28px;
}

.dm-banner-icon {
  font-size: 22px;
  background: #fff;
  color: #116AF8;
  padding: 10px 10px;
  border-radius: 10px;
  box-shadow: 0 2px 8px rgba(17, 106, 248, 0.15);
}

/* ================================
GRID (RECTANGLE CARDS)
================================ */

.dm-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(520px,1fr));
  gap: 22px;
}

/* ================================
CARD DESIGN
================================ */

.dm-card {
  background: rgba(255,255,255,.95);
  border: 1px solid #e5e7eb;
  border-radius: 16px;
  padding: 22px;
  backdrop-filter: blur(6px);
  box-shadow: 0 12px 10px rgba(17, 106, 248, 0.08);
  transition: .25s ease;
  position: relative;
  transform-style: preserve-3d;
  will-change: transform, box-shadow;
}

/* MAIN HOVER EFFECT */

.dm-card:hover {
  transform: translateY(-10px) scale(1.02);
  box-shadow:
    0 20px 40px rgba(17, 106, 248, 0.25),
    0 0 0 1px rgba(155, 192, 252, 0.4) inset;
}

/* GRADIENT BORDER GLOW */

.dm-card::before {
  content: "";
  position: absolute;
  inset: -1px;
  border-radius: inherit;
  background: linear-gradient(
    120deg,
    rgba(17, 106, 248, 0.4),
    rgba(155, 192, 252, 0.3),
    transparent 70%
  );
  opacity: 0;
  transition: opacity .35s ease;
  z-index: -1;
}

.dm-card:hover::before {
  opacity: 1;
}

/* ================================
CARD HEADER
================================ */

.dm-card-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  position: relative;
  overflow: hidden;
}

.dm-card-header h3 {
  margin: 0;
  font-size: 20px;
  color: #0A50F5;
}

.dm-url {
  font-size: 14px;
  color: #64748b;
  margin-top: 4px;
}

/* LIGHT SWEEP EFFECT */

.dm-card-header::after {
  content: "";
  position: absolute;
  top: 0;
  left: -120%;
  width: 80%;
  height: 100%;
  background: linear-gradient(
    110deg,
    transparent,
    rgba(155, 192, 252, 0.5),
    transparent
  );
  transform: skewX(-20deg);
}

.dm-card:hover .dm-card-header::after {
  animation: cardSweep .8s ease forwards;
}

@keyframes cardSweep {
  to { left: 140%; }
}

/* ================================
STATUS BADGE
================================ */

.dm-status {
  padding: 4px 12px;
  border-radius: 999px;
  font-size: 12px;
  font-weight: 600;
}

.dm-status.success {
  background: #E8F1FE;
  color: #0A50F5;
  border: 1px solid #9BC0FC;
}

.dm-status.danger {
  background: #fee2e2;
  color: #dc2626;
}

.dm-card:hover .dm-status.success {
  box-shadow: 0 0 14px rgba(17, 106, 248, 0.4);
}

.dm-card:hover .dm-status.danger {
  box-shadow: 0 0 14px rgba(239, 68, 68, 0.4);
}

/* ================================
CARD BODY
================================ */

.dm-card-body {
  display: flex;
  justify-content: space-between;
  margin-top: 18px;
}

.dm-info label {
  font-size: 12px;
  color: #64748b;
}

.dm-info div {
  font-weight: 500;
  margin-top: 3px;
  color: #1e293b;
}

/* Divider */

.dm-divider {
  border: none;
  border-top: 1px solid #e5e7eb;
  margin: 18px 0;
}

/* ================================
BUTTONS
================================ */

.dm-actions {
  display: flex;
  gap: 10px;
}

.dm-btn {
  border: none;
  padding: 7px 14px;
  border-radius: 9px;
  font-weight: 500;
  cursor: pointer;
  transition: .2s ease;
  position: relative;
}

.dm-btn:active {
  transform: scale(.95);
}

/* CONNECT */

.dm-btn.connect {
  background: linear-gradient(135deg, #E8F1FE, #D4E4FD);
  color: #0A50F5;
  border: 1px solid #9BC0FC;
}

.dm-btn.connect:hover {
  background: linear-gradient(135deg, #D4E4FD, #9BC0FC);
  box-shadow: 0 4px 12px rgba(17, 106, 248, 0.3);
  transform: translateY(-1px);
}

/* EDIT */

.dm-btn.edit {
  background: #f1f5f9;
  color: #334155;
}

.dm-btn.edit:hover {
  background: #e2e8f0;
  transform: translateY(-1px);
}

/* DELETE */

.dm-btn.delete {
  background: #fee2e2;
  color: #dc2626;
}

.dm-btn.delete:hover {
  background: #fecaca;
  animation: dmPulse .6s ease;
}

@keyframes dmPulse {
  0% { transform: scale(1); }
  50% { transform: scale(1.06); }
  100% { transform: scale(1); }
}

/* ================================
EMPTY STATE
================================ */

.dm-empty-state {
  grid-column: 1/-1;
  display: flex;
  justify-content: center;
}

.dm-empty-card {
  text-align: center;
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 40px;
  border: 2px dashed #9BC0FC;
  border-radius: 14px;
  background: linear-gradient(135deg, #F5F9FE, #EBF3FE);
}


/* ================================
PAGE FADE ANIMATION
================================ */

@keyframes dmFadeIn {
  from {
    opacity: 0;
    transform: translateY(8px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* =========================
   ADVANCED LOADER
========================= */

.dm-adv-loader-overlay {
  position: fixed;
  inset: 0;
  background: linear-gradient(180deg, #F4F7FE, #EAF0FC);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 99999;
}

.dm-adv-loader-card {
  width: 420px;
  padding: 30px;
  border-radius: 22px;
  background: rgba(255,255,255,0.95);
  backdrop-filter: blur(10px);
  box-shadow: 0 30px 60px rgba(10,80,245,0.25);
  text-align: center;
}

/* HEADER */
.dm-adv-loader-header {
  display: flex;
  justify-content: space-between;
  margin-bottom: 20px;
}

.dm-adv-loader-left {
  display: flex;
  gap: 10px;
  align-items: center;
}

.dm-logo-glow {
  position: absolute;
  width: 60px;
  height: 60px;
  background: radial-gradient(circle, #116AF8, transparent);
  filter: blur(20px);
}

.dm-small-label {
  font-size: 10px;
  color: #116AF8;
  letter-spacing: 2px;
}

.dm-title {
  font-size: 16px;
  font-weight: 600;
}

/* CIRCLE */
.dm-circle-wrap {
  position: relative;
  width: 120px;
  height: 120px;
  margin: 20px auto;
}

.dm-circle-wrap svg {
  transform: rotate(-90deg);
}

.track {
  fill: none;
  stroke: #eef2fb;
  stroke-width: 8;
}

.progress {
  fill: none;
  stroke: #116AF8;
  stroke-width: 8;
  stroke-linecap: round;
  transition: stroke-dashoffset 0.3s;
}

.dm-center {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  font-size: 22px;
  font-weight: 600;
}

.dm-center span {
  font-size: 10px;
  color: #999;
}

/* STAGE */
.dm-stage {
  margin-top: 10px;
  font-size: 18px;
}

.dm-sub {
  font-size: 13px;
  color: #64748b;
}

/* STAGES */
.dm-stage-bar {
  display: flex;
  margin-top: 20px;
  gap: 5px;
}

.stage {
  flex: 1;
  text-align: center;
}

.bar {
  height: 4px;
  background: #e5e7eb;
}

.bar.active {
  background: #116AF8;
}

.bar.done {
  background: #0A50F5;
}

.label {
  font-size: 10px;
  margin-top: 5px;
}

/* STATS */
.dm-stats {
  display: flex;
  justify-content: space-between;
  margin-top: 20px;
  background: #eef4ff;
  padding: 10px;
  border-radius: 12px;
}

.dm-stats span {
  font-size: 10px;
  color: #64748b;
}

.dm-stats b {
  display: block;
}

sp_widget.script:
(function() {

    data.side = $sp.getWidget('tracenow_sidebar');
    data.cons = [];

    /* =========================
       CREATE NOTIFICATION HANDLER
    ========================== */
    if (input && input.action == "createNotification") {
        var notif = new GlideRecordSecure("x_sysus_tracenow_notifications");
        notif.initialize();
        notif.setValue("title", input.payload.title);
        notif.setValue("message", input.payload.message);
        notif.setValue("type", input.payload.type);
        notif.setValue("priority", input.payload.priority);
        notif.setValue("user", gs.getUserID());
        notif.setValue("read", false);
        notif.insert();
        data.notificationCreated = true;
        return;
    }

    /* =========================
       CONNECTION HEALTH CHECK
    ========================== */
    if (input && input.action == "checkConnectionHealth") {
        data.connectionLost = false;
        var conn = new GlideRecordSecure("x_sysus_tracenow_connection");
        conn.addQuery("sys_created_by", gs.getUserName());
        conn.query();
        if (!conn.hasNext()) {
            data.connectionLost = true;
            data.instanceName = "Unknown instance";
        }
        return;
    }

/* ========================= DELETE RECORD ========================= */
if (input && input.action === "deleteRecord") {
    var dr = new GlideRecordSecure('x_sysus_tracenow_connection');
    dr.addQuery('sys_id', input.sys_id);
    dr.addQuery('sys_created_by', gs.getUserName());
    dr.query();

    if (dr.next()) {
        dr.deleteRecord();
        data.success = true;
    } else {
        data.success = false;
        data.error = "Record not found or unauthorized";
    }
    return;
}

/* ========================= CHECK CONNECTION STATUS ========================= */
if (input && input.action == "check") {
    data.success = false;
    try {
        var r = new sn_ws.RESTMessageV2();
        r.setHttpMethod("get");
        r.setEndpoint(input.url + "/api/now/table/sys_user?sysparm_limit=1");
        r.setBasicAuth(input.user, input.pass);
        r.setRequestHeader("Accept", "application/json");

        var response = r.execute();
        if (response.getStatusCode() == 200) {
            var userName = gs.getUserName();

            // Bulk deactivate others — unchanged, already correct
            var reset = new GlideRecordSecure("x_sysus_tracenow_connection");
            reset.addQuery("sys_created_by", userName);
            reset.addQuery("sys_id", "!=", input.sys_id);
            reset.query();
            while (reset.next()) {
                reset.setValue("state", false);
                reset.update();
            }

            // Activate current — replaced .get() with addQuery
            var current = new GlideRecordSecure("x_sysus_tracenow_connection");
            current.addQuery("sys_id", input.sys_id);
            current.addQuery("sys_created_by", userName);
            current.query();

            if (current.next()) {
                current.setValue("state", true);
                current.update();
                data.success = true;
            } else {
                data.success = false;
                data.error = "Connection record not found or unauthorized";
            }
        }
    } catch (ex) {
        data.error = ex.message;
    }
    return;
}

    /* =========================
       LOAD USER CONNECTION LIST
    ========================== */
    var gr = new GlideRecordSecure('x_sysus_tracenow_connection');
    gr.addQuery('sys_created_by', gs.getUserName());
    gr.query();
    while (gr.next()) {
        data.cons.push({
            name: gr.getValue('name'),
            url: gr.getValue('url'),
            user: gr.getValue('username'),
            state: gr.getValue('state') == '1' || gr.getValue('state') == 'true',
            date: gr.getDisplayValue('sys_updated_on'),
            sys_id: gr.getUniqueValue(),
            pass: gr.getValue('password')
        });
    }

})();
